import React from 'react';
import {
  AllocationVarianceConfirmModal,
  SalesVoucherFormShell,
  VoucherFormBodySkeleton,
  VoucherFormFooterSkeleton,
  VoucherFormStatusGroup,
  VoucherFormToolbar,
  VoucherMoneyFooter,
  VoucherPrintModal,
  VoucherSearchSlideout,
} from '../../../components/voucher';
import { HoaDonHeaderSection } from '../../../components/bh/HoaDonHeaderSection';
import { InvoicePaymentSection } from '../../../components/bh/InvoicePaymentSection';
import { LinkedReceiptSlideout } from '../../../components/bh/LinkedReceiptSlideout';
import { InvoiceLinesGrid, useMaterialLinesSelection } from '../../../components/form';
import { HeaderDiscountClearConfirmModal, UnsavedChangesModal } from '../../../components/form';
import { useHoaDonFormPage } from '../../../hooks/useHoaDonFormPage';
import { insertLineFieldErrors, removeLineFieldErrors } from '../../../utils/invoiceFieldValidation';
import { formatProcessingLevelFromOptions } from '../../../utils/voucherProcessingLevelOptions';
import { emptyInvoiceLine } from '../../../utils/orderLines';
import { VoucherPostedLedgerModal } from '../../../components/voucher/VoucherPostedLedgerModal';
import { bhService } from '../../../services/bh/bhService';
import { DocumentHistoryModal, Button, Modal, getActiveCompanyCode, getAuthUser, getCompanyBranding } from '@linm-soft-org/linm-web-common-components';
import { InvoiceValidationBanner } from '../../../components/bh/InvoiceValidationBanner';
import df from '../../../styles/documentForm.module.css';

const HoaDonFormPage: React.FC = () => {
  const vm = useHoaDonFormPage();
  const { copyLine, lineRowProps, setSelectedLineIndex } = useMaterialLinesSelection(vm.lines, vm.setLines);

  const addLine = () => {
    vm.setLines(prev => [...prev, emptyInvoiceLine()]);
    setSelectedLineIndex(vm.lines.length);
    // Re-index line errors after insert
    vm.setFieldErrors(prev => ({
      ...prev,
      lineErrors: insertLineFieldErrors(prev.lineErrors, vm.lines.length),
    }));
  };

  const removeLine = (idx: number) => {
    vm.setLines(prev => {
      const next = prev.filter((_, i) => i !== idx);
      return next.length ? next : [emptyInvoiceLine()];
    });
    setSelectedLineIndex(Math.max(0, idx - 1));
    // Re-index line errors after remove
    vm.setFieldErrors(prev => ({
      ...prev,
      lineErrors: removeLineFieldErrors(prev.lineErrors, idx),
    }));
  };

  const processingLevelLabel = formatProcessingLevelFromOptions(
    vm.processingLevel,
    vm.processingLevelOptions,
  );

  // ── Cross-company badge ──
  const activeCompanyCode = getActiveCompanyCode();
  const authUser = getAuthUser();
  const userHasMultipleCompanies = authUser?.canViewAllCompanies
    || authUser?.role === 'admin'
    || (authUser?.allowedCompanyCodes?.length ?? 0) > 0;
  const showBadge = userHasMultipleCompanies && !!(vm.voucherCompanyCode || activeCompanyCode);
  const badgeCompanyCode = vm.voucherCompanyCode || activeCompanyCode || '';
  const companyBranding = getCompanyBranding();
  const badgeLabel = companyBranding?.code === badgeCompanyCode && companyBranding?.shortName
    ? companyBranding.shortName
    : badgeCompanyCode;

  const toolbar = (
    <div className={df.stickyTop}>
      <VoucherFormToolbar
        testIdPrefix={vm.TEST_ID}
        insetShell
        title={vm.isNew ? 'Tạo hóa đơn' : `Hóa đơn — ${vm.invoiceCode || '...'}`}
        processingLevelBadge={
          !vm.isNew ? <VoucherFormStatusGroup processingLevelLabel={processingLevelLabel} /> : undefined
        }
        companyBadge={showBadge ? (
          <span
            style={{
              display: 'inline-flex',
              alignItems: 'center',
              gap: 4,
              padding: '2px 8px',
              borderRadius: 4,
              fontSize: 12,
              fontWeight: 600,
              background: '#e0f2fe',
              color: '#0369a1',
              border: '1px solid #7dd3fc',
              whiteSpace: 'nowrap',
            }}
            title={`Đơn vị hoạch toán: ${badgeCompanyCode}`}
          >
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" style={{ marginRight: 2 }}>
              <rect x="2" y="3" width="20" height="14" rx="2" ry="2" />
              <line x1="8" y1="21" x2="16" y2="21" />
              <line x1="12" y1="17" x2="12" y2="21" />
            </svg>
            {badgeLabel}
          </span>
        ) : undefined}
        formMode={vm.toolbarMode}
        viewModeHint={vm.viewModeHint}
        showApproveButton={false}
        canApprove={false}
        showPostButton={false}
        canPost={false}
        canCopy={!vm.isNew}
        canPrint={!vm.isNew}
        canHistory={!vm.isNew && !!vm.documentHistoryType}
        copySourceVoucherCode={vm.copySourceVoucherCode}
        canViewLedger={vm.canViewLedger}
        onViewLedger={() => vm.setShowLedgerModal(true)}
        showEditButton={vm.showEditDelete}
        showDeleteButton={vm.showEditDelete}
        showNewButton={vm.canCreate}
        canEdit={vm.showEditDelete}
        canDelete={vm.showEditDelete}
        canSave={vm.isNew ? vm.canCreate : vm.canUpdate}
        saving={vm.saving}
        searchNav={vm.hasSearchNav ? {
          index: vm.searchNavIndex,
          total: vm.searchResultIds.length,
          onFirst: () => vm.navigateToSearchId(vm.searchResultIds[0]),
          onPrev: () => vm.navigateToSearchId(vm.searchResultIds[vm.searchNavIndex - 1]),
          onNext: () => vm.navigateToSearchId(vm.searchResultIds[vm.searchNavIndex + 1]),
          onEnd: () => vm.navigateToSearchId(vm.searchResultIds[vm.searchResultIds.length - 1]),
        } : undefined}
        saveLabel={vm.isNew ? 'Tạo hóa đơn' : 'Lưu'}
        onBack={vm.handleBack}
        onApprove={() => {}}
        onPost={() => {}}
        onCopy={vm.handleCopy}
        onPrint={() => vm.setShowPrintModal(true)}
        onHistory={() => vm.setShowHistoryModal(true)}
        onSearch={() => vm.setShowSearchSlideout(true)}
        onNew={() => vm.navigate('/bh/hoa-don/them')}
        onEdit={vm.handleEdit}
        onSave={vm.handleSave}
        onCancel={vm.handleCancel}
        onDelete={() => vm.setShowDeleteModal(true)}
        canViewLinkedVoucher={vm.canViewLinkedReceipts}
        onViewLinkedVoucher={() => vm.setShowLinkedReceiptSlideout(true)}
        viewLinkedVoucherLabel="Xem phiếu thu"
        disabledReasons={vm.toolbarDisabledReasons}
        editingHint={vm.editingHint}
      />
    </div>
  );

  if (vm.loading) {
    return (
      <SalesVoucherFormShell
        testIdPrefix={vm.TEST_ID}
        header={toolbar}
        footer={<VoucherFormFooterSkeleton testIdPrefix={vm.TEST_ID} />}
      >
        <VoucherFormBodySkeleton testIdPrefix={vm.TEST_ID} />
      </SalesVoucherFormShell>
    );
  }

  return (
    <>
      <SalesVoucherFormShell
        testIdPrefix={vm.TEST_ID}
        header={toolbar}
        footer={(
          <VoucherMoneyFooter
            testIdPrefix={vm.TEST_ID}
            rows={[
              { id: 'productTotal', label: 'Tổng tiền:', amount: vm.totals.productTotal },
              { id: 'tax', label: 'Thuế:', amount: vm.totals.taxAmount },
              { id: 'netTotal', label: 'Thành tiền:', amount: vm.totals.total, emphasize: true },
            ]}
            discount={{
              displayAmount: vm.discountDisplayTotal,
              headerDiscountAmount: vm.headerDiscountAmount,
              useHeaderDiscount: vm.useHeaderDiscount,
              onUseHeaderDiscountChange: vm.setUseHeaderDiscount,
              onHeaderDiscountAmountChange: vm.setHeaderDiscountAmount,
              allocation: vm.headerDiscountAllocation,
              onAllocationChange: vm.setHeaderDiscountAllocation,
              hasLineDiscount: vm.lineDiscountActive,
              readOnly: !vm.canEditLines,
            }}
            variance={{
              amount: vm.varianceAmount,
              onAmountChange: vm.setVarianceAmount,
              readOnly: !vm.canEditLines,
            }}
            processingLevel={vm.processingLevel}
            onProcessingLevelChange={vm.setProcessingLevel}
            processingLevelOptions={vm.processingLevelOptions}
            processingLevelDisabled={vm.fieldLock.selectDisabled}
          />
        )}
      >
        <InvoiceValidationBanner
          validationErrors={vm.validationErrors}
          bannerClosed={vm.bannerClosed}
          bannerExpanded={vm.bannerExpanded}
          setBannerExpanded={vm.setBannerExpanded}
          setBannerClosed={vm.setBannerClosed}
          validationBannerId={vm.validationBannerId}
          tid={vm.tid}
        />
        <HoaDonHeaderSection
          testIdPrefix={vm.TEST_ID}
          headerExpanded={vm.headerExpanded}
          setHeaderExpanded={vm.setHeaderExpanded}
          columns={5}
          fieldLock={vm.fieldLock}
          invoiceDate={vm.invoiceDate}
          onInvoiceDateChange={vm.setInvoiceDate}
          invoiceCode={vm.invoiceCode}
          isNew={vm.isNew}
          customerId={vm.customerId}
          customerCode={vm.customerCode}
          customerName={vm.customerName}
          onCustomerSelect={vm.customerHandlers.onSelect}
          onCustomerClear={vm.customerHandlers.onClear}
          taxCode={vm.taxCode}
          onTaxCodeChange={vm.setTaxCode}
          description={vm.description}
          onDescriptionChange={vm.setDescription}
          shiftName={vm.shiftName}
          cashierName={vm.cashierName}
          legacyCode={vm.legacyCode}
          fieldErrors={vm.fieldErrors}
          onFieldErrorChange={vm.patchInvoiceFieldError}
        />
        <InvoicePaymentSection
          testIdPrefix={vm.TEST_ID}
          payments={vm.payments}
          viewSectionClass={vm.fieldLock.viewSectionClass}
        />
        <div className={[df.section, df.linesSection, vm.fieldLock.viewSectionClass].filter(Boolean).join(' ')}>
          <h2 className={df.sectionTitle}>Chi tiết hàng hóa</h2>
          <InvoiceLinesGrid
            lines={vm.lines}
            canEdit={vm.canEditLines}
            onChange={vm.setLines}
            patchLine={vm.patchLine}
            onAddLine={addLine}
            onCopyLine={copyLine}
            lineRowProps={lineRowProps}
            onRemoveLine={removeLine}
            lineErrors={vm.lineErrors}
            onLineFieldErrorChange={vm.patchInvoiceLineFieldError}
            testIdPrefix={vm.TEST_ID}
          />
        </div>
      </SalesVoucherFormShell>

      <UnsavedChangesModal
        isOpen={vm.showUnsavedModal}
        onStay={vm.cancelLeave}
        onLeave={vm.confirmLeave}
        data-testid={`${vm.TEST_ID}-unsaved-modal`}
      />

      <AllocationVarianceConfirmModal
        isOpen={vm.showVarianceConfirm}
        varianceAmount={vm.varianceAmount}
        onCancel={() => vm.setShowVarianceConfirm(false)}
        onConfirm={vm.confirmVarianceSave}
        data-testid={`${vm.TEST_ID}-variance-modal`}
      />

      <HeaderDiscountClearConfirmModal
        isOpen={vm.showHeaderDiscountClearConfirm}
        onStay={vm.cancelHeaderDiscountClear}
        onConfirm={vm.confirmHeaderDiscountClear}
        data-testid={`${vm.TEST_ID}-header-discount-clear-modal`}
      />

      {vm.invoiceId && vm.showLedgerModal ? (
        <VoucherPostedLedgerModal
          isOpen={vm.showLedgerModal}
          onClose={() => vm.setShowLedgerModal(false)}
          voucherTitle={`Hóa đơn ${vm.invoiceCode || '...'}`}
          testIdPrefix={vm.TEST_ID}
          fetchPostedLedger={() => bhService.getInvoicePostedLedger(vm.invoiceId!)}
          fetchPostingStatus={async () => {
            const ps = await bhService.getInvoicePostingStatus(vm.invoiceId!);
            return { postingStatus: ps.postingStatus, lastError: ps.lastError };
          }}
        />
      ) : null}

      <LinkedReceiptSlideout
        isOpen={vm.showLinkedReceiptSlideout}
        onClose={() => vm.setShowLinkedReceiptSlideout(false)}
        receipts={vm.linkedReceipts}
        onOpenReceipt={vm.handleOpenLinkedReceipt}
        testIdPrefix={vm.TEST_ID}
      />

      <VoucherPrintModal
        isOpen={vm.showPrintModal}
        onClose={() => vm.setShowPrintModal(false)}
        voucherTitle={!vm.isNew ? `Hóa đơn — ${vm.invoiceCode || '...'}` : undefined}
        onPrint={vm.handlePrint}
        printing={vm.printing}
        testIdPrefix={vm.TEST_ID}
      />

      {vm.showHistoryModal && vm.documentHistoryType && vm.invoiceId && (
        <DocumentHistoryModal
          isOpen={vm.showHistoryModal}
          onClose={() => vm.setShowHistoryModal(false)}
          client={vm.documentHistoryClient}
          documentType={vm.documentHistoryType}
          documentId={vm.invoiceId}
          documentCode={vm.invoiceCode || undefined}
          testIdPrefix={vm.TEST_ID}
        />
      )}

      <VoucherSearchSlideout
        isOpen={vm.showSearchSlideout}
        onClose={() => vm.setShowSearchSlideout(false)}
        title="Tìm hóa đơn"
        testIdPrefix={vm.TEST_ID}
        listScope="bh-hoa-don-search"
        fetchList={async (filter) => {
          const res = await bhService.getInvoices(filter);
          return { items: res.items, totalCount: res.totalCount };
        }}
        onOpenVoucher={vm.handleOpenFromSearch}
        processingLevelFilterOptions={vm.processingLevelOptions}
        formatProcessingLevel={level => formatProcessingLevelFromOptions(level, vm.processingLevelOptions)}
      />

      <Modal isOpen={vm.showDeleteModal} onClose={() => vm.setShowDeleteModal(false)} title="Xác nhận xóa hóa đơn">
        <p>Bạn có chắc muốn xóa hóa đơn này? Hành động không thể hoàn tác.</p>
        <div className={df.modalActions}>
          <Button variant="secondary" onClick={() => vm.setShowDeleteModal(false)}>Hủy</Button>
          <Button variant="danger" onClick={vm.handleDelete} loading={vm.deleting}>Xóa</Button>
        </div>
      </Modal>
    </>
  );
};

export default HoaDonFormPage;
