import React from 'react';
import styles from '../../styles/documentForm.module.css';

interface InvoiceValidationBannerProps {
  validationErrors: string[];
  bannerClosed: boolean;
  bannerExpanded: boolean;
  setBannerExpanded: React.Dispatch<React.SetStateAction<boolean>>;
  setBannerClosed: React.Dispatch<React.SetStateAction<boolean>>;
  validationBannerId: string;
  tid: (suffix: string) => string;
}

export const InvoiceValidationBanner: React.FC<InvoiceValidationBannerProps> = ({
  validationErrors,
  bannerClosed,
  bannerExpanded,
  setBannerExpanded,
  setBannerClosed,
  validationBannerId,
  tid,
}) => {
  if (validationErrors.length === 0 || bannerClosed) return null;
  return (
    <div
      id={validationBannerId}
      className={styles.errorBanner}
      data-testid={validationBannerId}
      role="alert"
    >
      <div className={styles.errorBannerBody}>
        <div className={styles.errorBannerHeader}>
          <strong>{validationErrors.length} lỗi cần xử lý</strong>
          <div className={styles.errorBannerActions}>
            <button
              type="button"
              className={styles.errorBannerToggle}
              onClick={() => setBannerExpanded(v => !v)}
            >
              {bannerExpanded ? '▲ Thu gọn' : '▼ Chi tiết'}
            </button>
            <button
              type="button"
              className={styles.errorBannerClose}
              onClick={() => setBannerClosed(true)}
            >
              ✕
            </button>
          </div>
        </div>
        <div
          className={[
            styles.errorListCollapse,
            bannerExpanded ? styles.errorListCollapseExpanded : '',
          ].filter(Boolean).join(' ')}
          aria-hidden={!bannerExpanded}
        >
          <ul className={`${styles.errorList} ${styles.errorListInner}`}>
            {validationErrors.map((e, i) => (
              <li key={`${i}-${e}`} data-testid={tid(`validation-error-${i}`)}>{e}</li>
            ))}
          </ul>
        </div>
      </div>
    </div>
  );
};
