import React from 'react';
import { Input } from '@linm-soft-org/linm-web-common-components';
import type { FormFieldLockResult } from '../form';
import { fieldPlaceholder } from '../form/FormMode';
import type { CustomerDto } from '../../services/master/models';
import { CustomerSearchField } from '../search';
import {
  CurrencyPairField,
  RequiredMark,
  SalesVoucherHeaderSection,
  VoucherFormRow,
} from '../voucher';
import type { InvoiceFieldErrors } from '../../utils/invoiceFieldValidation';
import df from '../../styles/documentForm.module.css';
import layout from '../../styles/hoaDonHeaderLayout.module.css';

const CURRENCY_OPTIONS = [{ value: 'VND', label: 'VND - Việt Nam đồng' }];

export type HoaDonHeaderSectionProps = {
  testIdPrefix: string;
  headerExpanded: boolean;
  setHeaderExpanded: React.Dispatch<React.SetStateAction<boolean>>;
  fieldLock: FormFieldLockResult;
  invoiceDate: string;
  onInvoiceDateChange: (value: string) => void;
  invoiceCode: string;
  isNew: boolean;
  customerId: string;
  customerCode: string;
  customerName: string;
  onCustomerSelect: (c: CustomerDto) => void;
  onCustomerClear: () => void;
  taxCode: string;
  onTaxCodeChange: (value: string) => void;
  description: string;
  onDescriptionChange: (value: string) => void;
  shiftName?: string;
  cashierName?: string;
  legacyCode?: string;
  /** @default 4 */
  columns?: 4 | 5 | 6;
  /** Field-level errors (Pattern B) */
  fieldErrors?: InvoiceFieldErrors;
  /** Per-field re-validation on change (Pattern B) */
  onFieldErrorChange?: (key: keyof InvoiceFieldErrors, value: string) => void;
};

/** Header 2 dòng row5 — `voucher-form-header-lines.md` · `hoa-don-ban-header-compact-map.md` */
export const HoaDonHeaderSection: React.FC<HoaDonHeaderSectionProps> = ({
  testIdPrefix,
  headerExpanded,
  setHeaderExpanded,
  fieldLock,
  invoiceDate,
  onInvoiceDateChange,
  invoiceCode,
  isNew,
  customerId,
  customerCode,
  customerName,
  onCustomerSelect,
  onCustomerClear,
  taxCode,
  onTaxCodeChange,
  description,
  onDescriptionChange,
  shiftName,
  cashierName,
  legacyCode,
  columns = 4,
  fieldErrors = {},
  onFieldErrorChange,
}) => {
  const {
    formMode,
    isStatusLocked,
    viewSectionClass,
    fieldLockProps,
    staticFieldProps,
    searchDisabled,
    searchViewClass,
  } = fieldLock;
  const ph = (text: string) => fieldPlaceholder(formMode, text, { isStatusLocked });
  const hasOptionalFields = !!(shiftName || cashierName || legacyCode);
  const sectionClassName = [layout.headerGrid5, !headerExpanded && layout.headerGrid5Compact].filter(Boolean).join(' ');
  const fieldsFlowClassName = !headerExpanded ? layout.headerFieldsFlowCompact : '';

  /** onChange + re-validate */
  const handleDateChange = (value: string) => {
    onInvoiceDateChange(value);
    onFieldErrorChange?.('invoiceDate', value);
  };
  const handleCustomerChange = (customer: CustomerDto) => {
    onCustomerSelect(customer);
    onFieldErrorChange?.('customerId', customer.customerId);
  };
  const handleCustomerClear = () => {
    onCustomerClear();
    onFieldErrorChange?.('customerId', '');
  };
  const handleDescriptionChange = (value: string) => {
    onDescriptionChange(value);
    onFieldErrorChange?.('description', value);
  };

  return (
    <SalesVoucherHeaderSection
      title="Thông tin hóa đơn"
      testIdPrefix={testIdPrefix}
      headerExpanded={headerExpanded}
      setHeaderExpanded={setHeaderExpanded}
      columns={columns}
      viewSectionClass={viewSectionClass}
      sectionClassName={sectionClassName}
      fieldsFlowClassName={fieldsFlowClassName}
    >
      {({ fieldClass, compactHideClass, formRowStyles }) => (
        <>
          {/* Row 1: Ngày HĐ · Số HĐ · NT/TG · Ca bán · Thu ngân (5 cột parity PT/PC) */}
          <VoucherFormRow styles={formRowStyles} columns={columns}>
            <div
              className={fieldClass(compactHideClass(true))}
              data-testid={`${testIdPrefix}-field-invoiceDate`}
            >
              <label className={df.label}>Ngày hóa đơn<RequiredMark /></label>
              <Input
                type="date"
                value={invoiceDate}
                error={fieldErrors.invoiceDate}
                onChange={e => handleDateChange(e.target.value)}
                {...(isNew ? fieldLockProps : staticFieldProps)}
              />
            </div>
            <div
              className={fieldClass(compactHideClass(false))}
              data-testid={`${testIdPrefix}-field-code`}
            >
              <label className={df.label}>Số hóa đơn</label>
              <Input
                value={invoiceCode}
                placeholder={ph('Tự động sinh')}
                {...staticFieldProps}
              />
            </div>
            <CurrencyPairField
              className={fieldClass(compactHideClass(false))}
              testIdPrefix={testIdPrefix}
              currencyCode="VND"
              exchangeRate={1}
              currencyOptions={CURRENCY_OPTIONS}
              staticFieldProps={staticFieldProps}
              selectDisabled={staticFieldProps.disabled}
            />
            {shiftName ? (
              <div
                className={fieldClass(compactHideClass(false))}
                data-testid={`${testIdPrefix}-field-shiftName`}
              >
                <label className={df.label}>Ca bán</label>
                <Input value={shiftName} {...staticFieldProps} />
              </div>
            ) : null}
            {cashierName ? (
              <div
                className={fieldClass(compactHideClass(false))}
                data-testid={`${testIdPrefix}-field-cashierName`}
              >
                <label className={df.label}>Thu ngân</label>
                <Input value={cashierName} {...staticFieldProps} />
              </div>
            ) : null}
          </VoucherFormRow>

          {/* Row 2: Khách hàng (spanCol2) · MST · Diễn giải (spanCol2) */}
          <VoucherFormRow styles={formRowStyles} columns={columns}>
            <div
              className={fieldClass(df.spanCol2, compactHideClass(true))}
              data-testid={`${testIdPrefix}-field-customerId`}
            >
              <label className={df.label}>Khách hàng<RequiredMark /></label>
              <CustomerSearchField
                customerId={customerId}
                customerCode={customerCode}
                customerName={customerName}
                error={fieldErrors.customerId}
                onSelect={handleCustomerChange}
                onClear={handleCustomerClear}
                disabled={searchDisabled}
                className={[df.lookupCodeMax150, searchViewClass].filter(Boolean).join(' ')}
                placeholder={ph('Nhập mã hoặc tên khách hàng...')}
                testIdPrefix={`${testIdPrefix}-customer`}
              />
            </div>
            <div
              className={fieldClass(compactHideClass(false))}
              data-testid={`${testIdPrefix}-field-taxCode`}
            >
              <label className={df.label}>Mã số thuế</label>
              <Input
                value={taxCode}
                onChange={e => onTaxCodeChange(e.target.value)}
                placeholder={ph('Nhập mã số thuế...')}
                {...fieldLockProps}
              />
            </div>
            <div
              className={fieldClass(df.spanCol2, compactHideClass(false))}
              data-testid={`${testIdPrefix}-field-description`}
            >
              <label className={df.label}>Diễn giải</label>
              <Input
                value={description}
                error={fieldErrors.description}
                onChange={e => handleDescriptionChange(e.target.value)}
                placeholder={ph('Nhập diễn giải...')}
                {...fieldLockProps}
              />
            </div>
          </VoucherFormRow>

          {/* Row 3 (optional): Mã gốc */}
          {hasOptionalFields && !shiftName && !cashierName && legacyCode ? (
            <VoucherFormRow styles={formRowStyles} columns={columns}>
              <div
                className={fieldClass(compactHideClass(false))}
                data-testid={`${testIdPrefix}-field-legacyCode`}
              >
                <label className={df.label}>Mã gốc</label>
                <Input value={legacyCode} {...staticFieldProps} />
              </div>
            </VoucherFormRow>
          ) : null}
        </>
      )}
    </SalesVoucherHeaderSection>
  );
};
