import { scrollToValidationTarget } from '@linm-soft-org/linm-web-common-components';

function scrollToFieldById(id: string): void {
  scrollToValidationTarget(id, 80);
}

export type InvoiceLineFieldKey = 'materialCode' | 'quantity' | 'unitPrice';
export type InvoiceLineFieldErrors = Partial<Record<InvoiceLineFieldKey, string>>;

export type InvoiceFieldErrors = {
  invoiceDate?: string;
  customerId?: string;
  description?: string;
  /** Banner-only error khi không có dòng nào */
  lines?: string;
  /** Per-line errors keyed by row index */
  lineErrors?: Record<number, InvoiceLineFieldErrors>;
};

export type InvoiceValidateInput = {
  invoiceDate?: string;
  customerId?: string;
  requireCustomerId?: boolean;
  customerLabel?: string;
  description?: string;
  linesCount: number;
  /** Lines to validate per-row errors (materialCode, quantity, unitPrice) */
  lines?: { materialCode?: string; quantity?: number; unitPrice?: number }[];
};

/** Collect banner-ready messages from field-level errors (excluding per-line errors) */
export function collectBannerMessages(fieldErrors: InvoiceFieldErrors): string[] {
  const msgs: string[] = [];
  const err = fieldErrors.invoiceDate;
  if (err) msgs.push(err);
  const err2 = fieldErrors.customerId;
  if (err2) msgs.push(err2);
  const err3 = fieldErrors.description;
  if (err3) msgs.push(err3);
  return msgs;
}

/** Pattern B: only show inline error after first save attempt */
export function applyInlineValidationMessage(
  validationAttempted: boolean,
  message: string | undefined,
): string | undefined {
  if (!validationAttempted) return undefined;
  return message;
}

function validateRow(rowIdx: number, row: { materialCode?: string; quantity?: number; unitPrice?: number }): InvoiceLineFieldErrors {
  const errs: InvoiceLineFieldErrors = {};

  if (!row.materialCode?.trim()) {
    errs.materialCode = `Dòng ${rowIdx + 1}: chưa chọn hàng hóa`;
    // quantity/unitPrice không validate khi chưa có material (line đang empty)
    return errs;
  }

  if (!row.quantity || row.quantity <= 0) {
    errs.quantity = `Dòng ${rowIdx + 1}: số lượng phải > 0`;
  }
  if (!row.unitPrice || row.unitPrice <= 0) {
    errs.unitPrice = `Dòng ${rowIdx + 1}: đơn giá phải > 0`;
  }

  return errs;
}

export function validateInvoiceFields(input: InvoiceValidateInput): {
  fieldErrors: InvoiceFieldErrors;
  bannerMessages: string[];
} {
  const fieldErrors: InvoiceFieldErrors = {};
  const bannerMessages: string[] = [];

  // invoiceDate required
  if (!input.invoiceDate?.trim()) {
    const msg = 'Ngày hóa đơn là bắt buộc';
    fieldErrors.invoiceDate = msg;
    bannerMessages.push(msg);
  }

  // customerId required
  if (input.requireCustomerId && !input.customerId?.trim()) {
    const label = input.customerLabel?.trim() || 'Khách hàng';
    const msg = `${label} là bắt buộc`;
    fieldErrors.customerId = msg;
    bannerMessages.push(msg);
  }

  // description max length (500)
  if (input.description && input.description.length > 500) {
    const msg = `Diễn giải không được vượt quá 500 ký tự`;
    fieldErrors.description = msg;
    bannerMessages.push(msg);
  }

  // lines required + per-line validation
  if (input.linesCount === 0) {
    bannerMessages.push('Phải có ít nhất 1 dòng hàng hóa');
  }

  if (input.lines && input.lines.length > 0) {
    const lineErrors: Record<number, InvoiceLineFieldErrors> = {};
    input.lines.forEach((row, idx) => {
      const rowErrs = validateRow(idx, row);
      if (Object.keys(rowErrs).length > 0) {
        lineErrors[idx] = rowErrs;
      }
    });
    if (Object.keys(lineErrors).length > 0) {
      fieldErrors.lineErrors = lineErrors;
      // Add per-line errors to banner
      for (const idx of Object.keys(lineErrors).map(Number).sort()) {
        const errs = lineErrors[idx];
        for (const msg of Object.values(errs).filter(Boolean)) {
          bannerMessages.push(msg);
        }
      }
    }
  }

  return { fieldErrors, bannerMessages };
}

/** Validate a single header field — used by onChange re-validation */
export function validateInvoiceHeaderField(
  key: keyof InvoiceFieldErrors,
  value: string,
  customerLabel?: string,
): string | undefined {
  switch (key) {
    case 'invoiceDate':
      if (!value?.trim()) return 'Ngày hóa đơn là bắt buộc';
      return undefined;
    case 'customerId':
      if (!value?.trim()) return `${customerLabel || 'Khách hàng'} là bắt buộc`;
      return undefined;
    case 'description':
      if (value && value.length > 500) return 'Diễn giải không được vượt quá 500 ký tự';
      return undefined;
    default:
      return undefined;
  }
}

/** Validate a single line field — used by onChange re-validation */
export function validateInvoiceLineField(
  rowIdx: number,
  key: InvoiceLineFieldKey,
  value: string | number | undefined,
  /** Current materialCode value for the line (to skip qty/price when no material) */
  currentMaterialCode?: string,
): string | undefined {
  switch (key) {
    case 'materialCode':
      if (!value || (typeof value === 'string' && !value.trim())) return `Dòng ${rowIdx + 1}: chưa chọn hàng hóa`;
      return undefined;
    case 'quantity':
      // Chỉ validate quantity khi đã có vật tư
      if (!currentMaterialCode?.trim()) return undefined;
      if (typeof value !== 'number' || value <= 0) return `Dòng ${rowIdx + 1}: số lượng phải > 0`;
      return undefined;
    case 'unitPrice':
      // Chỉ validate unitPrice khi đã có vật tư
      if (!currentMaterialCode?.trim()) return undefined;
      if (typeof value !== 'number' || value <= 0) return `Dòng ${rowIdx + 1}: đơn giá phải > 0`;
      return undefined;
    default:
      return undefined;
  }
}

/** Shift line error indices after insert — parity PT/PC */
export function insertLineFieldErrors(
  lineErrors: Record<number, InvoiceLineFieldErrors> | undefined,
  insertAt: number,
): Record<number, InvoiceLineFieldErrors> | undefined {
  if (!lineErrors) return undefined;
  const shifted: Record<number, InvoiceLineFieldErrors> = {};
  for (const [k, v] of Object.entries(lineErrors)) {
    const idx = Number(k);
    if (idx >= insertAt) {
      shifted[idx + 1] = v;
    } else {
      shifted[idx] = v;
    }
  }
  return shifted;
}

/** Compact line error indices after remove — parity PT/PC */
export function removeLineFieldErrors(
  lineErrors: Record<number, InvoiceLineFieldErrors> | undefined,
  removeAt: number,
): Record<number, InvoiceLineFieldErrors> | undefined {
  if (!lineErrors) return undefined;
  const shifted: Record<number, InvoiceLineFieldErrors> = {};
  for (const [k, v] of Object.entries(lineErrors)) {
    const idx = Number(k);
    if (idx === removeAt) continue;
    if (idx > removeAt) {
      shifted[idx - 1] = v;
    } else {
      shifted[idx] = v;
    }
  }
  return Object.keys(shifted).length > 0 ? shifted : undefined;
}

export function scrollToFirstInvoiceFieldError(
  fieldErrors: InvoiceFieldErrors,
  tid: (suffix: string) => string,
  validationBannerId: string,
): void {
  // Priority header fields first
  const priority: (keyof InvoiceFieldErrors)[] = ['invoiceDate', 'customerId', 'description'];
  for (const key of priority) {
    const error = fieldErrors[key];
    if (error) {
      scrollToFieldById(tid(`field-${key}`));
      return;
    }
  }

  // Then scan line errors by index ascending
  if (fieldErrors.lineErrors) {
    const sortedIndices = Object.keys(fieldErrors.lineErrors).map(Number).sort();
    for (const rowIdx of sortedIndices) {
      const rowErrs = fieldErrors.lineErrors[rowIdx];
      // materialCode > quantity > unitPrice
      if (rowErrs.materialCode) {
        scrollToFieldById(tid(`line-${rowIdx}-material`));
        return;
      }
      if (rowErrs.quantity) {
        scrollToFieldById(tid(`line-${rowIdx}-quantity`));
        return;
      }
      if (rowErrs.unitPrice) {
        scrollToFieldById(tid(`line-${rowIdx}-unitPrice`));
        return;
      }
    }
  }

  // Fallback: banner
  scrollToValidationTarget(validationBannerId, 16);
}
